INSERT INTO `questions` VALUES ('AHGF-20210711-01','总书记要求干部要做到心有所畏、言有所戒、行有所止。请你结合实际执法工作，谈谈“心”“言”“行”之间的关系。','legal','安徽',90,180,'[{\"score\": 8.0, \"content\": \"①内涵理解\"}, {\"score\": 10.0, \"content\": \"②三者关系论述\"}, {\"score\": 8.0, \"content\": \"③执法工作结合\"}, {\"score\": 6.0, \"content\": \"④岗位践行表态\"}]','{\"_meta\": {\"tags\": [\"安徽省考\", \"2021.7.11\", \"执法岗\", \"综合分析\", \"心有所畏言有所戒行有所止\", \"法治素养\", \"执法规范\", \"安徽执法\", \"长江大保护\", \"食品安全\", \"生态执法\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGF-20210711-01.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 17.6, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 22.4, \"min_score\": 17.7, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 27.2, \"min_score\": 22.5, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 32.0, \"min_score\": 27.3, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"心有所畏\", \"言有所戒\", \"行有所止\", \"执法\", \"规范\", \"程序正当\", \"法治\"], \"positionTags\": [\"general\"], \"questionType\": \"综合分析·法治素养·执法岗\", \"bonusKeywords\": [\"严格规范公正文明执法\", \"权责法定\", \"执法为民\", \"法治安徽\", \"生态执法\", \"现场处置\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"安徽\", \"执法人员\", \"敬畏法律\", \"文明执法\", \"法无授权不可为\", \"一改两为\", \"长江大保护\", \"食品安全\"], \"referenceAnswer\": \"（执法岗·安徽本土） 总书记“心有所畏、言有所戒、行有所止”的重要要求，是新时代执法干部的立身之本、履职之要、行权之规，对安徽基层执法工作具有极强的指导性与实践性。结合执法工作实际，“心”“言”“行”三者辩证统一、相辅相成、不可分割。 第一，心有所畏是“魂”，是思想前提与根本遵循。心有所畏，就是要始终敬畏国家法律、敬畏人民群众、敬畏公权力、敬畏组织纪律。作为安徽执法人员，只有心中高悬法律明镜，牢记长江大保护、食品安全、生态监管等法定职责，才能在执法中不任性、不滥权、不越界，始终坚守法治信仰与为民初心。 第二，言有所戒是“表”，是履职载体与形象窗口。执法先言、言为心声，语言是执法权威的直接体现。在开展现场检查、调查取证、告知处罚、宣传普法时，必须用语规范、表述精准、态度文明、逻辑清晰，坚决不说越权话、粗暴话、随意话、情绪化话，用规范语言亮明身份、告知依据、释法明理，展现安徽执法队伍良好作风与文明形象。 第三，行有所止是“果”，是行权边界与实践落点。行有所止，就是严格恪守法无授权不可为、法定职责必须为，执法检查、调查取证、行政强制、处罚决定等所有环节，必须符合法定权限、法定程序、法定要求。在安徽矿山治理、巢湖周边执法、食品安全抽检等工作中，坚决杜绝选择性执法、随意性执法、人情执法，做到规范用权、公正执法。 第四，三者紧密联系、有机统一。心有所畏决定言有所戒，言有所戒保障行有所止，行有所止反过来检验心有所畏。作为安徽执法人员，必须做到心中有法、口中有尺、行中有界、肩上有责，把敬畏、戒惧、底线融入日常执法全过程，实现政治效果、法律效果、社会效果有机统一。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-01/reference_high.txt\", \"expected_max\": 32.0, \"expected_min\": 29.0, \"llmExpectedMax\": 32.0, \"llmExpectedMin\": 29.0}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=template_analysis_mid_1，句数=6，截断=none，关键词削弱=medium。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-01/reference_mid.txt\", \"expected_max\": 16.0, \"expected_min\": 11.5, \"llmExpectedMax\": 17.4, \"llmExpectedMin\": 13.5}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=template_analysis_low_1，句数=5，截断=none，关键词削弱=medium，口语化=是。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-01/reference_low.txt\", \"expected_max\": 13.0, \"expected_min\": 8.5, \"llmExpectedMax\": 13.0, \"llmExpectedMin\": 8.1}], \"sourceQuestionId\": \"AHGF-20210711-01\"}, \"bonus\": [\"严格规范公正文明执法\", \"权责法定\", \"执法为民\", \"法治安徽\", \"生态执法\", \"现场处置\"], \"scoring\": [\"心有所畏\", \"言有所戒\", \"行有所止\", \"执法\", \"规范\", \"程序正当\", \"法治\", \"安徽\", \"执法人员\", \"敬畏法律\", \"文明执法\", \"法无授权不可为\", \"一改两为\", \"长江大保护\", \"食品安全\"], \"deducting\": []}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGF-20210711-02','某地有一家采矿企业，其许可证尚未到期，但当地为了践行总书记“绿水青山就是金山银山”的理念，要停止开发商的开采权。请问，如果由你负责，你会怎样处理好这项工作？','emergency','安徽',90,180,'[{\"score\": 10.0, \"content\": \"①依法处置原则\"}, {\"score\": 8.0, \"content\": \"②生态理念落实\"}, {\"score\": 8.0, \"content\": \"③稳妥有序推进\"}, {\"score\": 6.0, \"content\": \"④生态修复与长效机制\"}]','{\"_meta\": {\"tags\": [\"安徽省考\", \"2021.7.11\", \"执法岗\", \"生态执法\", \"矿山关停\", \"两山理念\", \"依法行政\", \"安徽生态\", \"长江大保护\", \"营商环境\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGF-20210711-02.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 17.6, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 22.4, \"min_score\": 17.7, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 27.2, \"min_score\": 22.5, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 32.0, \"min_score\": 27.3, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"采矿企业\", \"许可证\", \"生态保护\", \"关停\", \"依法行政\", \"两山理念\"], \"positionTags\": [\"general\"], \"questionType\": \"应急执法·生态治理·执法岗\", \"bonusKeywords\": [\"经济社会发展全面绿色转型区\", \"有序退出\", \"过渡期监管\", \"法治营商环境\", \"一改两为\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"安徽\", \"长江大保护\", \"生态修复\", \"柔性执法\", \"一刀切\", \"营商环境\", \"生态补偿\", \"绿色转型\"], \"referenceAnswer\": \"（执法岗·安徽生态） 处理此事必须坚持依法行政为底线、生态优先为导向、稳妥有序为路径、柔性执法为方法，既坚决守护安徽绿水青山，也依法保障企业合法权益，坚决杜绝简单粗暴“一刀切”执法。 第一，全面核查底数，固定法定依据。立即全面核查企业采矿许可证有效期限、开采范围、环保审批、生态影响评价、安全生产、税费缴纳等全部法定材料，对照《矿产资源法》《环境保护法》及安徽省矿山治理、长江大保护、生态修复相关政策，明确执法边界、政策依据、企业合法权益，形成完整核查台账。 第二，主动上门沟通，开展政策宣讲。第一时间约谈企业法定代表人、实际负责人，面对面宣传“绿水青山就是金山银山”重要理念，讲解安徽省长江经济带生态保护、矿山绿色转型、生态修复强制性要求，说明区域生态安全重要性与长远发展意义，争取企业理解、认同与主动配合。 第三，尊重合法权益，制定稳妥退出方案。鉴于企业许可证尚未到期，绝不违法强制关停，而是坚持协商原则、法治原则、补偿原则，联合自然资源、生态环境、财政、乡镇等部门，共同制定有序退出时间表、路线图、补偿方案、转型帮扶措施，落实安徽省生态补偿机制，保障企业合法财产权益与合理诉求。 第四，强化过渡期监管，严守生态底线。在退出过渡期内，严格开展日常执法检查，督促企业严格按照许可范围、环保标准、安全要求规范开采，严禁超层越界、违规开采、破坏生态、污染水土，一旦发现违法违规行为，立即依法从严查处。 第五，立即启动生态修复，筑牢安全屏障。企业停止开采后，第一时间组织开展矿山边坡治理、水土保持、植被复绿、土地复垦等生态修复工程，严格落实安徽省大别山、江淮分水岭、长江沿线生态修复标准，确保生态环境得到有效保护与修复。 第六，健全长效机制，推动绿色发展。以此为契机，完善辖区矿山准入、监管、退出全链条机制，严把生态环保准入关，推动产业绿色转型，助力安徽建设经济社会发展全面绿色转型区，实现生态效益、经济效益、社会效益有机统一。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-02/reference_high.txt\", \"expected_max\": 32.0, \"expected_min\": 29.0, \"llmExpectedMax\": 32.0, \"llmExpectedMin\": 29.0}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=spread，句数=6，截断=160，关键词削弱=light。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-02/reference_mid.txt\", \"expected_max\": 24.1, \"expected_min\": 19.1, \"llmExpectedMax\": 25.2, \"llmExpectedMin\": 19.2}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=spread，句数=4，截断=120，关键词削弱=medium，口语化=否。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-02/reference_low.txt\", \"expected_max\": 17.6, \"expected_min\": 12.6, \"llmExpectedMax\": 18.7, \"llmExpectedMin\": 12.5}], \"sourceQuestionId\": \"AHGF-20210711-02\"}, \"bonus\": [\"经济社会发展全面绿色转型区\", \"有序退出\", \"过渡期监管\", \"法治营商环境\", \"一改两为\"], \"scoring\": [\"采矿企业\", \"许可证\", \"生态保护\", \"关停\", \"依法行政\", \"两山理念\", \"安徽\", \"长江大保护\", \"生态修复\", \"柔性执法\", \"一刀切\", \"营商环境\", \"生态补偿\", \"绿色转型\"], \"deducting\": []}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGF-20210711-03','你去一家食品企业进行食品安全的调查，但是这个企业负责人为了拖延时间藏匿销毁证据，谎称跟你有矛盾，让你回避。此时，你会怎么处理？','legal','安徽',90,180,'[{\"score\": 4.0, \"content\": \"①程序规范回应\"}, {\"score\": 3.0, \"content\": \"②释法明理告知\"}, {\"score\": 4.0, \"content\": \"③证据固定处置\"}, {\"score\": 3.0, \"content\": \"④依法推进调查\"}, {\"score\": 2.0, \"content\": \"⑤后续依法处理\"}]','{\"_meta\": {\"tags\": [\"（完整不偷懒）安徽省考\", \"2021.7.11\", \"执法岗\", \"食品安全\", \"现场执法\", \"回避制度\", \"证据固定\", \"执法处置\", \"市场监管\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGF-20210711-03.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 8.8, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 11.2, \"min_score\": 8.9, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 13.6, \"min_score\": 11.3, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 16.0, \"min_score\": 13.7, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"食品安全\", \"调查\", \"回避\", \"证据\", \"执法\", \"阻碍执法\"], \"positionTags\": [\"market\"], \"questionType\": \"现场执法·食药安全·执法岗\", \"bonusKeywords\": [\"舌尖上的安全\", \"证据先行\", \"规范执法\", \"食品安全监管\", \"执法权威\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"藏匿销毁证据\", \"执法记录仪\", \"法定回避\", \"封存\", \"市场监管\", \"程序正当\"], \"referenceAnswer\": \"（执法岗·食安现场） 面对企业负责人恶意谎称矛盾、要求回避、意图拖延时间、藏匿销毁食品安全证据的情况，我会保持冷静、坚守程序、固定证据、依法处置，坚决确保食品安全调查依法有序推进，守护群众食品安全。 第一，保持理性冷静，规范回应回避申请。严格按照《行政处罚法》《市场监管执法程序规定》，当场明确告知企业负责人：回避制度有严格法定事由与法定申请流程，仅口头声称存在矛盾，不属于法定应当回避的情形，不符合回避要求，现场全程开启执法记录仪录音录像，固定言辞证据与现场情况。 第二，当场释法明理，告知法律后果。严肃向企业负责人宣讲食品安全监管法律法规，明确配合执法调查是企业法定义务，拖延调查、藏匿证据、销毁证据、阻碍执法均属于违法行为，需承担行政处罚乃至刑事责任，规劝其立即停止不当行为，主动配合调查。 第三，快速固定现场证据，严防销毁转移。在规范执法、确保程序正当前提下，立即对现场食品原料、生产加工环节、成品、进销货台账、检验记录、设备场所等逐一拍照、登记、封存、固定，坚决防止证据灭失，牢牢守住食品安全调查关键底线。 第四，依法依规推进调查，必要时请求协同支援。若企业仍拒不配合、继续阻碍执法，立即向上级汇报情况，请求同事到场协同执法，严格按照法定程序开展调查取证，确保调查不受干扰、不被拖延。 第五，规范完成调查，依法作出处理。全面查清食品安全相关事实，固定完整证据链，严格依据食品安全法作出处理；对企业阻碍执法、拒不配合行为，一并依法严肃处置，坚决维护执法权威与食品安全底线。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-03/reference_high.txt\", \"expected_max\": 16.0, \"expected_min\": 13.6, \"llmExpectedMax\": 16.0, \"llmExpectedMin\": 13.6}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=spread，句数=6，截断=160，关键词削弱=medium。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-03/reference_mid.txt\", \"expected_max\": 13.1, \"expected_min\": 8.6, \"llmExpectedMax\": 13.1, \"llmExpectedMin\": 9.5}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=spread，句数=5，截断=90，关键词削弱=heavy，口语化=是。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-03/reference_low.txt\", \"expected_max\": 9.0, \"expected_min\": 4.0, \"llmExpectedMax\": 9.0, \"llmExpectedMin\": 3.7}], \"sourceQuestionId\": \"AHGF-20210711-03\"}, \"bonus\": [\"舌尖上的安全\", \"证据先行\", \"规范执法\", \"食品安全监管\", \"执法权威\"], \"scoring\": [\"食品安全\", \"调查\", \"回避\", \"证据\", \"执法\", \"阻碍执法\", \"藏匿销毁证据\", \"执法记录仪\", \"法定回避\", \"封存\", \"市场监管\", \"程序正当\"], \"deducting\": []}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGF-20210711-04','有人说法不容情；有人说法亦有情，你怎么看？','legal','安徽',90,180,'[{\"score\": 5.0, \"content\": \"①辩证观点确立\"}, {\"score\": 4.0, \"content\": \"②法不容情论述\"}, {\"score\": 4.0, \"content\": \"③法亦有情论述\"}, {\"score\": 3.0, \"content\": \"④执法践行表态\"}]','{\"_meta\": {\"tags\": [\"安徽省考\", \"2021.7.11\", \"执法岗\", \"法治思辨\", \"法不容情法亦有情\", \"刚柔并济\", \"执法理念\", \"法治安徽\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGF-20210711-04.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 8.8, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 11.2, \"min_score\": 8.9, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 13.6, \"min_score\": 11.3, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 16.0, \"min_score\": 13.7, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"法不容情\", \"法亦有情\", \"法治\", \"刚柔并济\", \"执法\"], \"positionTags\": [\"general\"], \"questionType\": \"法治思辨·执法理念·执法岗\", \"bonusKeywords\": [\"法治安徽\", \"教育与处罚相结合\", \"柔性执法\", \"公平正义\", \"执法有温度\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"刚性\", \"温度\", \"执法为民\", \"文明执法\", \"法理情\", \"安徽\", \"一改两为\"], \"referenceAnswer\": \"（执法岗·法治理念） 我认为“法不容情”与“法亦有情”二者并不矛盾、辩证统一、相辅相成，共同构成新时代中国特色社会主义法治的核心内涵，更是安徽基层执法必须坚守的根本理念。 第一，法不容情，是法治的刚性底线与权威所在。法律是国家意志，是全体人民共同遵守的行为准则，具有普遍约束力、国家强制力、绝对权威性。坚持法不容情，就是坚持法律面前人人平等、以事实为依据、以法律为准绳，在安徽生态执法、食品安全执法、城市管理、矿山监管中，不徇私情、不搞特权、不搞选择性执法、不搞人情变通，执法必严、违法必究，坚决维护法治权威与社会公平正义。 第二，法亦有情，是法治的为民初心与温度体现。法律的本质是维护人民利益、服务社会发展，法治并非冷冰冰的处罚，而是法理与情理的统一、严格与文明的统一。坚持法亦有情，就是在执法中推行说理式执法、柔性执法、教育与处罚相结合，对轻微违法、首违轻微、无主观恶意的行为，多教育、多引导、多帮扶，少处罚、少强制、少机械，体现人文关怀，让群众感受到法治的温暖，契合安徽“一改两为、执法为民”要求。 第三，作为执法人员，必须坚持刚柔并济、法理情统一。在实际执法中，底线之上法不容情，执法之中法亦有情：对恶意违法、屡教不改、危害公共安全、侵害群众利益的行为，坚决严格执法、绝不姑息；对轻微违法、初次违法、主观无过错的行为，坚持教育为先、柔性处置。真正做到执法有力度、服务有温度、行权有尺度，让人民群众在每一起执法案件中都感受到公平正义。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-04/reference_high.txt\", \"expected_max\": 16.0, \"expected_min\": 13.6, \"llmExpectedMax\": 16.0, \"llmExpectedMin\": 13.6}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=spread，句数=7，截断=160，关键词削弱=medium。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-04/reference_mid.txt\", \"expected_max\": 13.1, \"expected_min\": 9.0, \"llmExpectedMax\": 13.1, \"llmExpectedMin\": 10.1}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=hybrid，句数=4，截断=90，关键词削弱=heavy，口语化=是。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGF-20210711-04/reference_low.txt\", \"expected_max\": 9.6, \"expected_min\": 4.6, \"llmExpectedMax\": 9.6, \"llmExpectedMin\": 4.3}], \"sourceQuestionId\": \"AHGF-20210711-04\"}, \"bonus\": [\"法治安徽\", \"教育与处罚相结合\", \"柔性执法\", \"公平正义\", \"执法有温度\"], \"scoring\": [\"法不容情\", \"法亦有情\", \"法治\", \"刚柔并济\", \"执法\", \"刚性\", \"温度\", \"执法为民\", \"文明执法\", \"法理情\", \"安徽\", \"一改两为\"], \"deducting\": []}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGWY-20201113PM-01','：习近平总书记说，我们中华民族在和灾害作斗争的过程中，斗了几千年，愚公移山、大禹治水，但是我们还要继续斗下去。这个斗不是跟老天爷作对，是人与自然要更加和谐，要顺随自然规律，更能够摸到自然规律，同时我们需要培养强大的抗御灾害能力。结合实际，谈谈你的看法。（32分）','analysis','安徽',90,180,'[{\"score\": 8.0, \"content\": \"内涵领悟\"}, {\"score\": 10.0, \"content\": \"实践践行\"}, {\"score\": 8.0, \"content\": \"公职立场与责任担当\"}, {\"score\": 4.0, \"content\": \"语言表达\"}, {\"score\": 2.0, \"content\": \"创新思维\"}]','{\"_meta\": {\"tags\": [\"安徽公务员\", \"省直市直县直岗\", \"综合分析题\", \"生态保护\", \"灾害防治\", \"人与自然和谐共生\", \"政治素养\", \"基层治理\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGWY-20201113PM-01.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 17.6, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 22.4, \"min_score\": 17.7, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 27.2, \"min_score\": 22.5, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 32.0, \"min_score\": 27.3, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"公务员\", \"人与自然和谐共生\", \"规律\", \"抗御灾害能力\", \"生态保护\", \"灾害防治\"], \"positionTags\": [\"township\"], \"questionType\": \"综合分析·观点类+生态治理+政治素养类\", \"bonusKeywords\": [\"生态+灾害协同防控\", \"新安江流域\", \"巢湖治理\", \"长效工作机制\", \"大别山生态保护\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"安徽\", \"基层治理\", \"民生安全\", \"长江大保护\", \"新安江流域\", \"责任担当\"], \"penaltyKeywords\": [\"理解偏差\", \"举措空泛\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"], \"referenceAnswer\": \"习近平总书记的重要论述，深刻揭示了人与自然的辩证关系，既传承了中华民族与灾害作斗争的优良传统，也为新时代生态保护与灾害防治工作指明了方向、提供了遵循，对安徽这样一个地处多流域、易受灾害影响的省份而言，具有极强的指导意义和实践价值。 对于总书记的论述，我认为必须深刻领悟、精准把握、务实践行，既要准确理解“斗”的内涵——不是与自然对抗，而是顺应规律、主动作为，也要明确“斗”的方向——既要守护生态和谐，也要提升抗灾能力，将论述精神融入安徽生态保护、灾害防治和基层治理的全过程、各方面，切实守护好人民群众的生命财产安全，推动安徽高质量发展。 第一，深刻领悟论述内涵，把握人与自然辩证关系。“愚公移山、大禹治水”的典故，彰显了中华民族不畏艰难、勇于抗争的精神，而总书记强调的“继续斗下去”，并非违背自然规律的盲目对抗，而是在尊重自然、顺应自然的基础上，主动防范灾害、守护生态平衡的责任担当。这要求我们始终坚持“绿水青山就是金山银山”的发展理念，既要摒弃“人定胜天”的盲目执念，也要杜绝“无所作为”的消极心态，做到敬畏自然、顺应规律、利用规律，实现人与自然和谐共生，这与安徽打造“经济社会发展全面绿色转型区”的定位高度契合。 第二，立足安徽实际，践行生态保护与灾害防治责任。安徽境内长江、淮河、新安江三大流域贯穿，洪涝、干旱、地质灾害等时有发生，同时安徽作为长三角生态屏障，生态保护责任重大。践行总书记重要论述，就是要结合安徽实际，双轮驱动、双向发力：一方面，持续推进生态保护修复，深入实施长江大保护、淮河生态治理、新安江流域生态补偿机制，加强湿地保护、水土保持，守护好安徽的绿水青山，让生态优势转化为发展优势；另一方面，健全灾害防控体系，完善灾害监测预警机制，加强防洪、抗旱、地质灾害防控等基础设施建设，开展灾害防治宣传培训，提升群众防灾、避灾、救灾能力，同时强化应急处置队伍建设，提升应急响应和处置水平，切实筑牢灾害防控安全防线，守护人民群众生命财产安全。 第三，强化责任担当，推动论述精神落地生根。作为安徽省公务员，我们是生态保护的践行者、灾害防治的推动者、民生安全的守护者，必须立足岗位、主动作为，将总书记重要论述转化为履职尽责的实际行动。一方面，要加强理论学习，深刻领悟总书记生态文明思想，提升自身政治素养和生态保护、灾害防治专业能力，主动学习安徽生态治理、灾害防控相关政策举措，熟悉岗位所需技能；另一方面，要立足岗位职能，主动深入基层、深入群众，开展生态保护宣传、灾害防治科普，倾听群众诉求，排查灾害隐患，协助解决群众在生态保护、灾害防控中的急难愁盼问题；同时，要主动担当作为，在灾害来临时，坚守岗位、冲锋在前，配合做好应急处置、群众转移安置等工作，切实履行好公职人员的责任与使命，推动总书记重要论述在安徽落地生根、开花结果。 总之，总书记的重要论述，为我们做好生态保护与灾害防治工作提供了根本遵循。作为新时代安徽省公务员，我们要深刻领悟、务实践行，既要坚守生态底线，推动人与自然和谐共生，也要强化灾害防控能力，筑牢安全防线，以实际行动守护好安徽的绿水青山，守护好人民群众的生命财产安全，为安徽高质量发展、建设“三地一区”贡献自己的力量。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-01/reference_high.txt\", \"expected_max\": 32.0, \"expected_min\": 29.0, \"llmExpectedMax\": 32.0, \"llmExpectedMin\": 29.0}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=template_analysis_mid_1，句数=6，截断=none，关键词削弱=medium。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-01/reference_mid.txt\", \"expected_max\": 14.8, \"expected_min\": 10.7, \"llmExpectedMax\": 16.4, \"llmExpectedMin\": 12.3}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=template_analysis_low_1，句数=5，截断=none，关键词削弱=medium，口语化=是。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-01/reference_low.txt\", \"expected_max\": 11.8, \"expected_min\": 7.7, \"llmExpectedMax\": 11.8, \"llmExpectedMin\": 7.1}], \"sourceQuestionId\": \"AHGWY-20201113PM-01\"}, \"bonus\": [\"生态+灾害协同防控\", \"新安江流域\", \"巢湖治理\", \"长效工作机制\", \"大别山生态保护\"], \"scoring\": [\"公务员\", \"人与自然和谐共生\", \"规律\", \"抗御灾害能力\", \"生态保护\", \"灾害防治\", \"安徽\", \"基层治理\", \"民生安全\", \"长江大保护\", \"新安江流域\", \"责任担当\"], \"deducting\": [\"理解偏差\", \"举措空泛\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"]}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGWY-20201113PM-02','：社区附近有一个小型养老院，收留空巢老人，但有居民举报养老院没有登记，有扰民现象，领导让你去解决，你会如何解决？（32分）','emergency','安徽',90,180,'[{\"score\": 8.0, \"content\": \"核查摸底\"}, {\"score\": 10.0, \"content\": \"整改处置\"}, {\"score\": 8.0, \"content\": \"公职立场与民生意识\"}, {\"score\": 4.0, \"content\": \"语言表达\"}, {\"score\": 2.0, \"content\": \"创新思维\"}]','{\"_meta\": {\"tags\": [\"安徽公务员\", \"省直市直县直社区岗\", \"应急应变题\", \"基层治理\", \"养老服务\", \"空巢老人\", \"扰民处置\", \"合规监管\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGWY-20201113PM-02.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 17.6, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 22.4, \"min_score\": 17.7, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 27.2, \"min_score\": 22.5, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 32.0, \"min_score\": 27.3, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"公务员\", \"养老院\", \"未登记\", \"扰民\", \"基层治理\", \"民生服务\"], \"positionTags\": [\"township\"], \"questionType\": \"应急应变·基层治理+民生服务+合规监管类\", \"bonusKeywords\": [\"三位一体处置模式\", \"15分钟养老服务圈\", \"网格化管理\", \"常态化沟通机制\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"空巢老人\", \"合规监管\", \"整改落实\", \"社区和谐\", \"安徽养老\"], \"penaltyKeywords\": [\"核查不全面\", \"举措空泛\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"], \"referenceAnswer\": \"社区小型养老院收留空巢老人，本是助力养老服务、关爱空巢老人的善举，但未登记、扰民问题，既违反了养老机构管理相关规定，也影响了社区居民的正常生活，若不及时妥善处置，不仅会激化邻里矛盾，还可能影响空巢老人的正常养老，违背安徽“积极应对人口老龄化、推进养老服务提质增效”的工作要求。 接到领导安排后，我会坚持“民生优先、合规有序、妥善处置、长效保障”的原则，快速介入、全面核查、分类施策，切实解决养老院未登记和扰民问题，兼顾空巢老人养老权益与社区居民生活需求，推动社区养老服务规范、健康发展。 第一，快速对接、全面核查，摸清问题根源。一方面，主动联系举报居民，耐心倾听其诉求，详细询问扰民的具体表现（如噪音、卫生、人员进出等）、发生时间、影响范围，做好记录，表达政府对其诉求的重视，承诺及时处置、给予反馈；另一方面，实地走访该小型养老院，与养老院负责人沟通，核查未登记的原因（如不了解登记流程、材料不齐全、不符合登记条件等），查看养老院的运营情况、居住环境、安全设施，询问老人的居住感受，同时走访养老院周边居民，核实扰民问题的真实性和严重程度，全面掌握问题全貌，形成详细的核查报告。 第二，分类施策、妥善处置，化解突出问题。针对核查出的两个核心问题，分步骤、有针对性地推进解决：一是解决未登记问题，若养老院符合登记条件但未办理登记，我会主动指导负责人准备相关材料（如资质证明、场地证明、人员资质等），协助其到民政部门办理登记手续，告知其登记流程、时限和相关要求，督促其尽快完成登记，做到合法合规运营；若养老院不符合登记条件（如场地不达标、无专业护理人员等），我会向负责人说明相关规定，明确整改要求和时限，协助其对接正规养老机构，妥善安置空巢老人，避免老人无家可归，同时依法依规责令其停止违规运营。二是解决扰民问题，针对噪音、卫生等具体扰民点，与养老院负责人协商制定整改措施：如合理规定老人活动时间，避免噪音干扰居民休息；加强养老院卫生管理，定期清理垃圾、消毒，改善居住环境；规范人员进出管理，避免外来人员随意进出，减少对社区的影响，同时组织养老院负责人与周边居民代表座谈，真诚道歉、说明整改措施，争取居民的理解和支持，化解邻里矛盾。 第三，跟踪督办、强化落实，确保问题闭环。整改期间，我会定期实地检查养老院的整改情况，跟踪登记手续办理进度和扰民问题整改效果，及时协调解决整改过程中出现的困难和问题；整改完成后，再次走访举报居民和周边居民，核实问题是否彻底解决，征求其意见和建议，确保整改到位、群众满意。同时，将整改情况形成报告，上报领导，接受领导监督。 第四，长效管控、优化服务，推动规范发展。结合此次问题处置，我会举一反三，联合民政、社区等相关部门，对辖区内小型养老机构开展一次全面排查，对未登记、不合规的养老机构逐一督促整改，建立台账、动态管理；同时，加强对养老机构的政策宣传和指导，普及登记流程、运营规范等相关知识，提升养老机构负责人的合规意识和服务水平；此外，加强社区协调，搭建养老机构与居民的沟通平台，建立常态化沟通机制，及时化解矛盾，推动养老服务与社区生活和谐共生，助力安徽养老服务体系不断完善，切实守护好空巢老人的养老权益，提升社区居民的幸福感和满意度。 总之，解决此类问题，既要坚持依法依规、规范管理，也要坚守民生初心、注重人文关怀，既要解决当前突出问题，也要建立长效机制，做到合规监管与民生服务兼顾，切实化解邻里矛盾，推动社区养老服务规范发展，彰显新时代安徽省公务员的责任与担当。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-02/reference_high.txt\", \"expected_max\": 32.0, \"expected_min\": 29.0, \"llmExpectedMax\": 32.0, \"llmExpectedMin\": 29.0}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=leading，句数=6，截断=160，关键词削弱=medium。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-02/reference_mid.txt\", \"expected_max\": 20.1, \"expected_min\": 15.1, \"llmExpectedMax\": 21.2, \"llmExpectedMin\": 15.2}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=spread，句数=7，截断=90，关键词削弱=heavy，口语化=否。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-02/reference_low.txt\", \"expected_max\": 12.9, \"expected_min\": 7.9, \"llmExpectedMax\": 14.7, \"llmExpectedMin\": 7.8}], \"sourceQuestionId\": \"AHGWY-20201113PM-02\"}, \"bonus\": [\"三位一体处置模式\", \"15分钟养老服务圈\", \"网格化管理\", \"常态化沟通机制\"], \"scoring\": [\"公务员\", \"养老院\", \"未登记\", \"扰民\", \"基层治理\", \"民生服务\", \"空巢老人\", \"合规监管\", \"整改落实\", \"社区和谐\", \"安徽养老\"], \"deducting\": [\"核查不全面\", \"举措空泛\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"]}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGWY-20201113PM-03','：市里要将废弃工厂改造成居民文化体验中心，谈谈你的创意方案，并具体展开。（16分）','practical','安徽',90,180,'[{\"score\": 4.8, \"content\": \"方案定位与理念\"}, {\"score\": 4.8, \"content\": \"公职立场与服务意识\"}, {\"score\": 4.8, \"content\": \"语言表达\"}, {\"score\": 1.6, \"content\": \"创新思维\"}]','{\"_meta\": {\"tags\": [\"安徽公务员\", \"省直市直县直岗\", \"组织管理题\", \"城市更新\", \"废弃工厂改造\", \"文化体验中心\", \"徽文化\", \"民生服务\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGWY-20201113PM-03.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 8.8, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 11.2, \"min_score\": 8.9, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 13.6, \"min_score\": 11.3, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 16.0, \"min_score\": 13.7, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"公务员\", \"废弃工厂\", \"文化体验中心\", \"民生服务\", \"城市更新\"], \"positionTags\": [\"general\"], \"questionType\": \"组织管理·创意方案+城市更新+民生服务类\", \"bonusKeywords\": [\"VR沉浸式体验\", \"政府主导+市场补充\", \"绿色低碳改造\", \"青少年文化实践基地\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"皖韵文化\", \"徽文化\", \"功能布局\", \"长效运营\", \"文化强省\", \"安徽\"], \"penaltyKeywords\": [\"定位偏差\", \"内容空泛\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"], \"referenceAnswer\": \"将废弃工厂改造为居民文化体验中心，是推进城市更新、盘活闲置资源、丰富居民精神文化生活、提升城市文化品位的重要举措，契合安徽“文化强省”建设和城市更新的工作要求，既能让废弃工厂“重获新生”，也能为居民提供优质的文化体验空间，实现“闲置资源利用+民生服务提升+文化传承发展”的多重效益。 结合安徽本土文化特色和居民实际需求，我设计的创意方案核心是“传承皖韵文化、服务全民需求、打造多元空间”，具体展开如下，确保方案科学合理、创意新颖、务实可行、长效可持续。 第一，方案核心定位与设计理念。核心定位：打造“皖韵文化体验+全民休闲服务+邻里互动交流”的综合性居民文化体验中心，立足安徽本土文化（如徽文化、黄梅戏、民俗文化等），兼顾不同年龄段、不同群体居民的需求，打造“有温度、有特色、可参与”的文化空间。设计理念：一是“修旧如旧、活化利用”，保留废弃工厂的原有建筑风貌（如厂房结构、烟囱、机床等），融入现代设计元素，实现工业记忆与文化体验的融合；二是“本土特色、彰显个性”，深度融入安徽徽文化、黄梅戏、民俗风情等元素，打造具有安徽辨识度的文化体验空间；三是“全民参与、便民惠民”，设置多元化功能区域，满足老人、青年、儿童等不同群体的文化需求，让文化体验中心成为居民的“精神家园”。 第二，前期筹备工作。一是调研摸底，深入了解废弃工厂的基本情况（如建筑面积、结构状况、闲置时间等），走访周边居民，通过问卷、座谈等方式，收集居民对文化体验中心的功能需求、文化偏好、使用习惯等，同时调研安徽其他地市废弃工厂改造的成功案例，借鉴先进经验；二是方案论证，邀请建筑设计师、文化专家、社区负责人、居民代表组成论证小组，对方案的可行性、创意性、实用性进行论证，结合各方意见修改完善方案，明确改造预算、工期、责任分工；三是手续办理，对接自然资源、住建、文化等相关部门，办理改造所需的审批手续，确保改造工作合法合规推进。 第三，具体改造内容与功能布局。结合废弃工厂原有结构，合理划分功能区域，融入安徽本土文化元素，打造多元化文化体验空间，具体分为5大区域：1.皖韵文化展示区：保留工厂原有厂房结构，设置徽文化展示墙、黄梅戏道具陈列柜、安徽民俗展品（如徽州三雕、剪纸、皮影等），通过图文、实物、多媒体等形式，展示安徽本土文化魅力，同时设置互动体验区，让居民亲手体验剪纸、徽州三雕等民俗技艺，传承本土文化。2.全民阅读与学习区：划分成人阅读区、少儿阅读区、自习区，配备涵盖文学、历史、科普、安徽文化等类别的书籍，引入电子阅读设备，打造“沉浸式”阅读空间，同时定期开展读书分享会、文化讲座、安徽文化专题培训等活动，丰富居民精神文化生活。3.休闲娱乐与互动区：设置老年活动区（配备棋牌、健身器材、戏曲演唱设备）、青年休闲区（配备桌游、咖啡座、文创展示）、儿童游乐区（安全、益智的游乐设施），同时设置邻里交流厅，为居民提供互动交流的空间，定期开展邻里节、文化汇演等活动，拉近邻里关系。4.文创与便民服务区：引入安徽本土文创企业，设置文创产品展示销售区，展示销售徽州文创、黄梅戏文创等特色产品，同时设置便民服务站，提供复印打印、政策咨询、文化咨询等便民服务，提升服务实用性。5.工业记忆展示区：保留工厂原有机床、烟囱、生产工具等工业遗迹，打造工业记忆长廊，展示当地工业发展历程，让居民了解城市工业历史，传承工业精神。 第四，改造实施与质量管控。一是明确施工单位，通过公开招标选择具备资质、经验丰富的施工单位，签订施工合同，明确改造标准、工期、质量要求；二是强化质量管控，安排专人负责施工现场监管，定期检查施工质量，确保改造工程符合安全标准、环保标准和设计要求，同时注重施工安全，避免施工扰民；三是严控工期与预算，合理安排施工进度，确保按时完成改造，严格控制改造预算，避免浪费，确保资金高效利用。第五，后期运营与长效管理。一是建立运营管理机制，成立运营管理小组，由社区、文化部门、居民代表共同参与，明确管理职责，制定管理制度（如开放时间、安全管理、设备维护等）；二是丰富运营内容，定期开展文化体验、民俗活动、读书分享、文创交流等活动，吸引居民参与，提升文化体验中心的活跃度；三是强化宣传推广，通过社区公告、政务新媒体、居民群等渠道，宣传文化体验中心的功能、活动安排，提高居民知晓度和参与度；四是建立反馈机制，定期收集居民的意见和建议，及时优化功能布局、完善运营服务，确保文化体验中心能够持续发挥作用，真正惠及居民。 总之，该创意方案立足安徽本土文化特色和居民需求，兼顾创意性与实用性、改造与运营，既能盘活废弃资源、推进城市更新，也能丰富居民精神文化生活、传承安徽本土文化，助力安徽文化强省建设和民生改善，彰显新时代安徽省公务员的创新思维和服务为民的责任担当。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-03/reference_high.txt\", \"expected_max\": 16.0, \"expected_min\": 13.6, \"llmExpectedMax\": 16.0, \"llmExpectedMin\": 13.6}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=leading，句数=8，截断=160，关键词削弱=none。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-03/reference_mid.txt\", \"expected_max\": 12.6, \"expected_min\": 7.6, \"llmExpectedMax\": 13.1, \"llmExpectedMin\": 8.4}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=spread，句数=5，截断=90，关键词削弱=heavy，口语化=否。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-03/reference_low.txt\", \"expected_max\": 7.9, \"expected_min\": 2.9, \"llmExpectedMax\": 7.9, \"llmExpectedMin\": 2.6}], \"sourceQuestionId\": \"AHGWY-20201113PM-03\"}, \"bonus\": [\"VR沉浸式体验\", \"政府主导+市场补充\", \"绿色低碳改造\", \"青少年文化实践基地\"], \"scoring\": [\"公务员\", \"废弃工厂\", \"文化体验中心\", \"民生服务\", \"城市更新\", \"皖韵文化\", \"徽文化\", \"功能布局\", \"长效运营\", \"文化强省\", \"安徽\"], \"deducting\": [\"定位偏差\", \"内容空泛\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"]}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGWY-20201113PM-04','用“大渡河”“小岗村”“大湾区”这三个词，即兴说一段话。（赋分20分）','expression','安徽',90,180,'[{\"score\": 6.0, \"content\": \"词汇使用\"}, {\"score\": 6.0, \"content\": \"价值认知\"}, {\"score\": 6.0, \"content\": \"公职立场与本土关联\"}, {\"score\": 6.0, \"content\": \"语言表达\"}, {\"score\": 2.0, \"content\": \"创新思维\"}]','{\"_meta\": {\"tags\": [\"安徽公务员\", \"省直市直县直岗\", \"即兴表达题\", \"大渡河\", \"小岗村\", \"大湾区\", \"责任担当\", \"改革精神\", \"实干奋进\", \"为民服务\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGWY-20201113PM-04.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 14.3, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 18.2, \"min_score\": 14.4, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 22.1, \"min_score\": 18.3, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 26.0, \"min_score\": 22.2, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"公务员\", \"大渡河\", \"小岗村\", \"大湾区\", \"责任担当\", \"为民服务\"], \"positionTags\": [\"township\"], \"questionType\": \"即兴表达·价值认知+责任担当+语言表达类\", \"bonusKeywords\": [\"安徽乡村振兴\", \"三地一区\", \"岗位实践\", \"科创产业\", \"文旅融合\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"大渡河精神\", \"改革精神\", \"高质量发展\", \"安徽\", \"实干奋进\", \"长三角一体化\"], \"penaltyKeywords\": [\"词汇缺失\", \"生硬\", \"内涵解读偏差\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"], \"referenceAnswer\": \"大渡河的惊涛骇浪，见证了革命先辈不畏艰险、奋勇拼搏的奋斗征程，铸就了永不磨灭的大渡河精神；小岗村的“红手印”，镌刻着安徽人敢闯敢试、勇于突破的改革勇气，开启了中国农村改革的序幕；大湾区的蓬勃崛起，展现了新时代中国高质量发展的强劲动能，勾勒出区域协同发展的美好蓝图。 这三个关键词，串联起中国革命、改革、发展的壮阔历程，也为新时代安徽省公务员指明了前进方向、注入了精神力量。作为新时代安徽省公务员，我们要以大渡河精神为引领，传承革命先辈不畏艰难、敢于担当的优良作风，在基层治理、民生服务、急难险重任务中，勇挑重担、冲锋在前，不畏惧困难、不退缩逃避，以坚定的信念和务实的行动，破解工作中的痛点难点问题；要以小岗村改革精神为动力，立足安徽改革发展实际，打破思维定势、勇于创新突破，在岗位上践行改革理念，聚焦群众急难愁盼，推出务实举措，让改革成果真正惠及于民；要以大湾区发展为标杆，主动学习其先进发展经验、创新理念和务实作风，立足安徽“三地一区”建设定位，主动融入长三角一体化发展，以实干践初心、以担当促发展，把精神力量转化为推动安徽高质量发展的实际成效，用青春和汗水书写新时代公务员的责任与使命。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-04/reference_high.txt\", \"expected_max\": 26.0, \"expected_min\": 23.0, \"llmExpectedMax\": 26.0, \"llmExpectedMin\": 23.0}, {\"label\": \"程序化中档参考答案\", \"notes\": \"基于高分答案程序化压缩生成；策略=spread，句数=6，截断=160，关键词削弱=none。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-04/reference_mid.txt\", \"expected_max\": 22.5, \"expected_min\": 18.3, \"llmExpectedMax\": 22.5, \"llmExpectedMin\": 17.9}, {\"label\": \"程序化低档参考答案\", \"notes\": \"基于高分答案程序化降档生成；策略=leading，句数=3，截断=90，关键词削弱=medium，口语化=否。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201113PM-04/reference_low.txt\", \"expected_max\": 15.7, \"expected_min\": 10.7, \"llmExpectedMax\": 17.4, \"llmExpectedMin\": 10.4}], \"sourceQuestionId\": \"AHGWY-20201113PM-04\"}, \"bonus\": [\"安徽乡村振兴\", \"三地一区\", \"岗位实践\", \"科创产业\", \"文旅融合\"], \"scoring\": [\"公务员\", \"大渡河\", \"小岗村\", \"大湾区\", \"责任担当\", \"为民服务\", \"大渡河精神\", \"改革精神\", \"高质量发展\", \"安徽\", \"实干奋进\", \"长三角一体化\"], \"deducting\": [\"词汇缺失\", \"生硬\", \"内涵解读偏差\", \"脱离实际\", \"逻辑混乱\", \"立场偏差\", \"口语化严重\"]}','2026-05-08 21:29:20','2026-05-09 05:29:20'),('AHGWY-20201114-01','最美逆行者乘风破浪，比如一线抗疫工作者，他们体现工作担当责任，北斗导航工作者展现出来的智慧，请谈谈在你自己的岗位上如何做一个乘风破浪的青年？（32分）','analysis','安徽',90,180,'[{\"score\": 8.0, \"content\": \"榜样认知\"}, {\"score\": 10.0, \"content\": \"岗位实践\"}, {\"score\": 8.0, \"content\": \"青年担当\"}, {\"score\": 4.0, \"content\": \"语言表达\"}, {\"score\": 2.0, \"content\": \"创新思维\"}]','{\"_meta\": {\"tags\": [\"安徽公务员\", \"省直市直岗\", \"综合分析题\", \"青年担当\", \"乘风破浪\", \"岗位实践\", \"为民服务\", \"一改两为\", \"基层治理\"], \"source\": \"local_asset\", \"originFile\": \"ai_gongwu_backend/assets/questions/generated_anhui/AHGWY-20201114-01.json\", \"scoreBands\": [{\"label\": \"低分/偏弱\", \"max_score\": 17.6, \"min_score\": 0, \"description\": \"核心要点覆盖不足，结构或岗位适配明显欠缺。\"}, {\"label\": \"基本合格\", \"max_score\": 22.4, \"min_score\": 17.7, \"description\": \"能覆盖主要要求，但深度、结构或本土化仍有短板。\"}, {\"label\": \"中高档\", \"max_score\": 27.2, \"min_score\": 22.5, \"description\": \"内容较完整，逻辑较清晰，接近高分答案。\"}, {\"label\": \"高分标杆\", \"max_score\": 32.0, \"min_score\": 27.3, \"description\": \"高分参考答案区间，用于回归验证。\"}], \"sourceLabel\": \"本地真题\", \"coreKeywords\": [\"青年\", \"担当\", \"实干\", \"岗位\", \"为民服务\", \"榜样\", \"初心\", \"使命\"], \"positionTags\": [\"township\"], \"questionType\": \"综合分析·职业认知+青年担当+岗位实践类\", \"bonusKeywords\": [\"乘风破浪\", \"履职尽责\", \"实干笃行\", \"青年干部\", \"基层服务\"], \"sourceDocument\": \"2020-2025第二批次完全版.docx\", \"strongKeywords\": [\"安徽\", \"基层\", \"一改两为\", \"乡村振兴\", \"三地一区\", \"攻坚克难\", \"忠诚\"], \"penaltyKeywords\": [\"片面空谈\", \"立场偏差\", \"脱离实际\", \"逻辑混乱\", \"口语化严重\"], \"referenceAnswer\": \"新时代是奋斗者的时代，“乘风破浪”是青年一代最鲜明的精神标识。一线抗疫工作者以生命赴使命，用责任担当守护万家灯火； 北斗导航工作者以智慧铸重器，用创新拼搏挺起民族脊梁，他们是时代榜样，更是我们青年公职人员的行动指引。作为安徽省公务员，我将以榜样为镜、向先进看齐，立足岗位、实干笃行，努力做一名乘风破浪的新时代青年。 第一，筑牢信仰之基，把稳思想之舵。我将深入学习党的创新理论，坚定理想信念，增强“四个意识”、坚定“四个自信”、做到“两个维护”，把榜样精神转化为履职尽责的内在动力，把个人追求融入安徽“三地一区”建设、长三角一体化发展、乡村振兴等中心大局，始终做到心中有信仰、肩上有责任、脚下有力量，在大是大非面前立场坚定，在风浪考验面前无所畏惧。 第二，扛起担当之责，走好实干之路。我将牢记公职人员初心使命，坚持以人民为中心的发展思想，主动深入基层一线、走进群众身边，聚焦群众急难愁盼问题，把小事办实、把实事办好，不驰于空想、不骛于虚声。面对困难矛盾不回避、不退缩，面对急难险重任务豁得出、顶得上，发扬抗疫工作者的担当精神、北斗团队的钻研精神，在基层治理、民生服务、改革发展中勇挑重担、善作善成，以实干实绩守护群众利益、助力安徽发展。 第三，锤炼过硬本领，永葆进取之心。我将坚持勤学善思，向书本学、向实践学、向群众学，系统学习政策法规、业务知识、工作方法，不断提升群众工作、应急处置、改革创新等核心能力。同时，严守纪律规矩，知敬畏、存戒惧、守底线，清白做人、干净做事，勇于突破思维定势、创新工作方法，在学习中成长、在实践中进步，努力成为政治强、业务精、作风实、群众信得过的青年干部，以青春之我、奋斗之我，在新时代新征程中乘风破浪、建功立业。\", \"regressionCases\": [{\"label\": \"文档高分基准答案\", \"notes\": \"来自原始题库文档的核心采分基准答案。\", \"sample_path\": \"assets/regression_samples/generated_anhui/AHGWY-20201114-01/reference_high.txt\", \"expected_max\": 32.0, \"expected_min\": 29.0, \"llmEx